export function getCitiesByState(stateSlug: string): CityData[] {
  return cities.filter((city) => city.stateSlug === stateSlug);
}

export function getCityBySlug(stateSlug: string, citySlug: string): CityData | undefined {
  return cities.find((city) => city.stateSlug === stateSlug && city.slug === citySlug);
}

export function getAllCitySlugs(): { stateSlug: string; citySlug: string }[] {
  return cities.map((city) => ({
    stateSlug: city.stateSlug,
    citySlug: city.slug,
  }));
}
